fn main() {
    let b = Box::new(5);
    println!("b = {}", b);
    println!("b + 1 = {}", *b + 1);
    // Box is dropped here, heap memory freed
}

#[derive(Debug)]
enum List {
    Cons(i32, Box<List>),
    Nil,
}

use List::*;

fn main() {
    let list = Cons(1, Box::new(Cons(2, Box::new(Cons(3, Box::new(Nil))))));
    println!("{:?}", list);
}

use std::rc::Rc;

fn main() {
    let a = Rc::new(5);
    let b = Rc::clone(&a); // increments reference count
    let c = Rc::clone(&a);
    println!("count: {}", Rc::strong_count(&a));
    println!("{} {} {}", a, b, c);
    drop(b);
    println!("after drop: {}", Rc::strong_count(&a));
}

use std::cell::RefCell;

fn main() {
    let data = RefCell::new(vec![1, 2, 3]);

    // Borrow immutably
    println!("{:?}", data.borrow());

    // Borrow mutably
    data.borrow_mut().push(4);
    println!("{:?}", data.borrow());
}

use std::rc::Rc;
use std::cell::RefCell;

fn main() {
    let shared = Rc::new(RefCell::new(0));
    let a = Rc::clone(&shared);
    let b = Rc::clone(&shared);

    *a.borrow_mut() += 10;
    *b.borrow_mut() += 20;

    println!("{}", shared.borrow());
}

fn greet(name: &str) {
    println!("Hello, {}!", name);
}

fn main() {
    let boxed = Box::new(String::from("Rustacean"));
    greet(&boxed); // Box<String> auto-derefs to &str
}

struct Resource {
    name: String,
}

impl Drop for Resource {
    fn drop(&mut self) {
        println!("Dropping: {}", self.name);
    }
}

fn main() {
    let r1 = Resource { name: String::from("Database connection") };
    let r2 = Resource { name: String::from("File handle") };
    println!("Resources created");
} // r2 dropped first, then r1 (reverse order)

use std::rc::{Rc, Weak};

fn main() {
    let strong = Rc::new(42);
    let weak = Rc::downgrade(&strong);

    println!("strong count: {}", Rc::strong_count(&strong));
    println!("weak count: {}", Rc::weak_count(&strong));

    if let Some(val) = weak.upgrade() {
        println!("still alive: {}", val);
    }

    drop(strong);
    println!("upgraded after drop: {:?}", weak.upgrade());
}
